121: pub(crate) fn registered_tools(tcx: TyCtxt<'_>, (): ()) -> RegisteredTools {
122:     let (_, pre_configured_attrs) = &*tcx.crate_for_resolver(()).borrow();
123:     registered_tools_ast(tcx.dcx(), pre_configured_attrs)
124: }
